import{_ as t,o as d,c as a,ag as o}from"./chunks/framework.HG0H2VLS.js";const g=JSON.parse('{"title":"Badge — Figma Notes","description":"","frontmatter":{},"headers":[],"relativePath":"public/demos/src/components/Badge/Badge.figma-notes.md","filePath":"public/demos/src/components/Badge/Badge.figma-notes.md"}'),r={name:"public/demos/src/components/Badge/Badge.figma-notes.md"};function i(c,e,s,n,l,h){return d(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="badge-—-figma-notes" tabindex="-1">Badge — Figma Notes <a class="header-anchor" href="#badge-—-figma-notes" aria-label="Permalink to &quot;Badge — Figma Notes&quot;">​</a></h1><p><strong>Figma:</strong> <a href="https://www.figma.com/design/Lus07xi8pPXLN87sQIyrEt/Affino-AI---Design-System?node-id=2580-8904" target="_blank" rel="noreferrer"><code>node 2580:8904</code></a><strong>Tier:</strong> Component <strong>Files:</strong> <code>Badge.css</code>, <code>Badge.html</code>, <code>Badge.js</code>, <code>Badge.figma.ts</code>, <code>Badge.figma-notes.md</code></p><hr><h2 id="variant-matrix-verified-from-figma-get-metadata-2026-05-05" tabindex="-1">Variant matrix (verified from Figma <code>get_metadata</code> 2026-05-05) <a class="header-anchor" href="#variant-matrix-verified-from-figma-get-metadata-2026-05-05" aria-label="Permalink to &quot;Variant matrix (verified from Figma `get_metadata` 2026-05-05)&quot;">​</a></h2><p>The component set defines <strong>32 symbols</strong> — 6 Type axes × a partial State axis × Size only on Type=Default. The cells shown below are the only combinations Figma defines; absent cells (e.g. Type=Border + State=Default, Type=Icon Left + State=Neutral) are <strong>not</strong> in the component set.</p><table tabindex="0"><thead><tr><th>Type</th><th>States defined</th><th>Sizes defined</th><th>Total cells</th></tr></thead><tbody><tr><td>Default</td><td>Neutral, Success, Warning, Danger, Info (no Default)</td><td>Default</td><td>5</td></tr><tr><td>Border</td><td>Neutral, Success, Warning, Danger, Info</td><td>Default</td><td>5</td></tr><tr><td>Pill</td><td>Neutral, Success, Warning, Danger, Info</td><td>Default</td><td>5</td></tr><tr><td>Icon Left</td><td>Success, Warning, Danger, Info</td><td>Default</td><td>4</td></tr><tr><td>Indicator</td><td>Success, Neutral, Warning, Danger, Info</td><td>Default</td><td>5</td></tr><tr><td>Dismissible</td><td>Info, Success, Warning, Danger, Neutral</td><td>Default</td><td>5</td></tr><tr><td>Size demo (Type=Default, State=Default)</td><td>Default</td><td>sm, Default, lg</td><td>3</td></tr></tbody></table><p><strong>Key facts about the axes:</strong></p><ul><li><strong><code>State=Default</code> is only used as the canvas for the Size demo</strong> (Type=Default + State=Default <ul><li>sm/Default/lg). It is NOT one of the status states displayed in the regular state row. The regular states are 5: Neutral, Success, Warning, Danger, Info.</li></ul></li><li><code>Type=Icon Left</code> has only <strong>4 states</strong> (no Default, no Neutral).</li><li>The Size axis (<code>sm</code> / <code>Default</code> / <code>lg</code>) is only enumerated on the <code>Type=Default, State=Default</code> cell. All other cells are Size=Default. The CSS supports applying <code>--sm</code> / <code>--lg</code> to any state class, but Figma only specifies non-Default sizes for the Default state.</li></ul><p><strong>Two duplicate sub-frames in the parent:</strong> <code>2580:10544</code> (light preview) and <code>2580:10795</code> (dark preview) are mirror exports of the same component set rendered in the two themes. Both frames list the same 32 symbols.</p><hr><h2 id="css-class-mapping" tabindex="-1">CSS class mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS class mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma property</th><th>CSS class</th></tr></thead><tbody><tr><td>Type=Default</td><td>(no modifier — base <code>.badge</code>)</td></tr><tr><td>Type=Border</td><td><code>.badge--border</code></td></tr><tr><td>Type=Pill</td><td><code>.badge--pill</code></td></tr><tr><td>Type=Icon Left</td><td>(base layout — add <code>&lt;i data-lucide=&quot;…&quot;&gt;</code> child)</td></tr><tr><td>Type=Indicator</td><td><code>.badge--pill</code> (add <code>&lt;span class=&quot;badge__dot&quot;&gt;</code> child)</td></tr><tr><td>Type=Dismissible</td><td>(base layout — add <code>&lt;button class=&quot;badge__close&quot;&gt;</code> child)</td></tr><tr><td>State=Default</td><td><code>.badge--default</code></td></tr><tr><td>State=Neutral</td><td><code>.badge--neutral</code></td></tr><tr><td>State=Success</td><td><code>.badge--success</code></td></tr><tr><td>State=Warning</td><td><code>.badge--warning</code></td></tr><tr><td>State=Danger</td><td><code>.badge--danger</code></td></tr><tr><td>State=Info</td><td><code>.badge--info</code></td></tr><tr><td>Size=sm</td><td><code>.badge--sm</code></td></tr><tr><td>Size=Default</td><td>(base)</td></tr><tr><td>Size=lg</td><td><code>.badge--lg</code></td></tr></tbody></table><hr><h2 id="token-mapping-verified-per-variant" tabindex="-1">Token mapping (verified per variant) <a class="header-anchor" href="#token-mapping-verified-per-variant" aria-label="Permalink to &quot;Token mapping (verified per variant)&quot;">​</a></h2><h3 id="base-badge" tabindex="-1">Base (<code>.badge</code>) <a class="header-anchor" href="#base-badge" aria-label="Permalink to &quot;Base (`.badge`)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td><code>border</code></td><td><code>1px solid var(--ai-btn-primary-border)</code> (transparent token bound by Figma)</td></tr><tr><td><code>border-radius</code></td><td><code>var(--ai-radius-md)</code></td></tr><tr><td><code>padding</code></td><td><code>var(--ai-spacing-1) var(--ai-spacing-3)</code> (4px / 8px)</td></tr><tr><td><code>gap</code></td><td><code>var(--ai-spacing-2)</code> (6px)</td></tr><tr><td><code>font-family</code></td><td><code>var(--ai-font-title)</code></td></tr><tr><td><code>font-weight</code></td><td><code>var(--ai-font-semibold)</code></td></tr><tr><td><code>font-size</code></td><td><code>var(--ai-font-fixed-xxs)</code> (12px)</td></tr><tr><td><code>line-height</code></td><td><code>var(--ai-leading-xs)</code> (16px)</td></tr></tbody></table><h3 id="state-colour-pairs-used-by-default-pill-icon-left-indicator-dismissible-types" tabindex="-1">State colour pairs (used by Default, Pill, Icon Left, Indicator, Dismissible types) <a class="header-anchor" href="#state-colour-pairs-used-by-default-pill-icon-left-indicator-dismissible-types" aria-label="Permalink to &quot;State colour pairs (used by Default, Pill, Icon Left, Indicator, Dismissible types)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>State</th><th>Background</th><th>Text</th></tr></thead><tbody><tr><td>Default ★</td><td><code>--ai-surface-info-soft</code></td><td><code>--ai-text-info</code></td></tr><tr><td>Neutral</td><td><code>--ai-surface-neutral-soft</code></td><td><code>--ai-text-neutral</code></td></tr><tr><td>Success</td><td><code>--ai-surface-success-soft</code></td><td><code>--ai-text-success</code></td></tr><tr><td>Warning</td><td><code>--ai-surface-warning-soft</code></td><td><code>--ai-text-warning</code></td></tr><tr><td>Danger</td><td><code>--ai-surface-error-soft</code></td><td><code>--ai-text-error</code></td></tr><tr><td>Info</td><td><code>--ai-surface-brand-soft-extra</code> ⚠</td><td><code>--ai-text-info</code></td></tr></tbody></table><p>★ <strong>State=Default uses Info-family tokens</strong> (<code>--ai-surface-info-soft</code> background and <code>--ai-text-info</code> for text). Visually a muted-blue chip on a soft-blue field. State=Default is only used for the Size demonstration row in Figma — it is not a status state shown alongside Neutral/Success/etc. Note Default and Info now share the same text token (<code>--ai-text-info</code>) but differ in their background tokens (<code>surface-info-soft</code> vs <code>surface-brand-soft-extra</code>).</p><p>⚠ <strong>Info background binding:</strong> Figma binds the Info state&#39;s background to <code>--ai-surface-brand-soft-extra</code> and the text to <code>--ai-text-info</code>. The hex of <code>brand-soft-extra</code> and <code>info-soft</code> happen to match (#f0f3ff) at present, but they are semantically distinct tokens. Default and Info therefore use different background tokens even though the rendered colour is the same.</p><h3 id="type-border-transparent-bg-coloured-border" tabindex="-1">Type=Border (transparent bg, coloured border) <a class="header-anchor" href="#type-border-transparent-bg-coloured-border" aria-label="Permalink to &quot;Type=Border (transparent bg, coloured border)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>State</th><th>Border colour</th></tr></thead><tbody><tr><td>Neutral</td><td><code>--ai-border-neutral</code></td></tr><tr><td>Success</td><td><code>--ai-border-success</code></td></tr><tr><td>Warning</td><td><code>--ai-border-warning</code></td></tr><tr><td>Danger</td><td><code>--ai-border-error</code></td></tr><tr><td>Info</td><td><code>--ai-border-info</code></td></tr></tbody></table><p>Figma defines no Border+Default; the CSS no longer ships a <code>.badge--border.badge--default</code> rule.</p><h3 id="type-pill" tabindex="-1">Type=Pill <a class="header-anchor" href="#type-pill" aria-label="Permalink to &quot;Type=Pill&quot;">​</a></h3><p><code>border-radius: var(--ai-radius-full)</code> overrides the base radius. State colour pair unchanged.</p><h3 id="type-icon-left" tabindex="-1">Type=Icon Left <a class="header-anchor" href="#type-icon-left" aria-label="Permalink to &quot;Type=Icon Left&quot;">​</a></h3><p>Adds a 16px (<code>--ai-icon-size-sm</code>) Lucide icon as the first child. State colour pair unchanged. The icon uses <code>currentColor</code> so it inherits the badge text colour.</p><h3 id="type-indicator" tabindex="-1">Type=Indicator <a class="header-anchor" href="#type-indicator" aria-label="Permalink to &quot;Type=Indicator&quot;">​</a></h3><p>Adds a 6px (<code>--ai-spacing-2</code>) circular dot (<code>.badge__dot</code>) as the first child, using <code>background: currentColor</code> so the dot inherits the state&#39;s text colour. Indicator badges in Figma use <code>--ai-radius-full</code> (i.e. they&#39;re pill-shaped) — apply both <code>.badge--pill</code> and the state class.</p><h3 id="type-dismissible" tabindex="-1">Type=Dismissible <a class="header-anchor" href="#type-dismissible" aria-label="Permalink to &quot;Type=Dismissible&quot;">​</a></h3><p>Adds a trailing <code>&lt;button class=&quot;badge__close&quot;&gt;</code> containing a 16px (<code>--ai-icon-size-sm</code>) Lucide <code>x</code>. The button container is 20px (<code>--ai-icon-size-md</code>) circular with <code>opacity: 0.7</code> that goes to <code>1</code> on hover. JavaScript (<code>Badge.js</code>) auto-removes the parent badge when the close button is clicked.</p><p>The Dismissible variant container is 30px tall (vs 26px for the other types) — naturally derived from the 20px close button + 4px vertical padding + 1px×2 border. No CSS height override needed.</p><h3 id="sizes" tabindex="-1">Sizes <a class="header-anchor" href="#sizes" aria-label="Permalink to &quot;Sizes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Size</th><th>padding (V H)</th><th>font-size</th><th>line-height</th><th>Resulting height</th></tr></thead><tbody><tr><td>sm</td><td><code>0</code> <code>var(--ai-spacing-2)</code></td><td><code>--ai-font-fixed-xxs</code></td><td><code>--ai-leading-xs</code></td><td>18px</td></tr><tr><td>Default</td><td><code>var(--ai-spacing-1)</code> <code>var(--ai-spacing-3)</code></td><td><code>--ai-font-fixed-xxs</code></td><td><code>--ai-leading-xs</code></td><td>26px</td></tr><tr><td>lg</td><td><code>var(--ai-spacing-2)</code> <code>var(--ai-spacing-4)</code></td><td><code>--ai-font-fixed-xs</code></td><td><code>--ai-leading-sm</code></td><td>34px</td></tr></tbody></table><p><code>lg</code> overrides the icon size to <code>--ai-icon-size-md</code> (20px) for icons inside the badge.</p><hr><h2 id="token-gap-notes" tabindex="-1">Token gap notes <a class="header-anchor" href="#token-gap-notes" aria-label="Permalink to &quot;Token gap notes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Figma value</th><th>Token used</th><th>Note</th></tr></thead><tbody><tr><td>Base border</td><td>transparent</td><td><code>--ai-btn-primary-border</code></td><td>Figma binds this <code>btn-primary-border</code> token (named for buttons) on the badge. Followed exactly per the rule &quot;use the Figma variable as bound&quot;. Worth flagging to the designer for a more semantically generic name.</td></tr><tr><td>Size=sm padding-y</td><td><code>py-px</code> (1px) in Figma</td><td><code>0</code> in CSS</td><td>Figma&#39;s <code>1px</code> is not in our <code>--ai-spacing-*</code> scale. Using <code>0</code> produces the correct visible 18px height because the 1px border on top/bottom provides the same total. Visually identical.</td></tr></tbody></table><p>No other token gaps. No primitive Tailwind colours (Red/400 etc.) used.</p><hr><h2 id="sub-elements" tabindex="-1">Sub-elements <a class="header-anchor" href="#sub-elements" aria-label="Permalink to &quot;Sub-elements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Element</th><th>Class</th><th>Tokens / sizing</th></tr></thead><tbody><tr><td>Icon (Type=Icon Left)</td><td><code>&lt;i data-lucide=&quot;…&quot;&gt;</code> direct child</td><td><code>flex-shrink: 0</code>; size <code>--ai-icon-size-sm</code>; <code>lg</code> override → <code>--ai-icon-size-md</code></td></tr><tr><td>Dot (Type=Indicator)</td><td><code>.badge__dot</code></td><td>6px (<code>--ai-spacing-2</code>) square, <code>border-radius: full</code>, <code>background: currentColor</code></td></tr><tr><td>Close button (Type=Dismissible)</td><td><code>.badge__close</code></td><td>20px (<code>--ai-icon-size-md</code>) circular, <code>opacity: 0.7</code> → <code>1</code> on hover, contains a 16px Lucide <code>x</code></td></tr></tbody></table><hr><h2 id="javascript-badge-js" tabindex="-1">JavaScript (<code>Badge.js</code>) <a class="header-anchor" href="#javascript-badge-js" aria-label="Permalink to &quot;JavaScript (`Badge.js`)&quot;">​</a></h2><p>Single delegated <code>click</code> listener on <code>document</code> finds the closest <code>.badge__close</code> and removes its parent <code>.badge</code>. Event-delegated so it works for badges added to the DOM after page load. No init API beyond the auto-init on <code>DOMContentLoaded</code>.</p><hr><h2 id="link-badges-anchor-as-badge" tabindex="-1">Link badges (anchor as badge) <a class="header-anchor" href="#link-badges-anchor-as-badge" aria-label="Permalink to &quot;Link badges (anchor as badge)&quot;">​</a></h2><p><code>a.badge</code> gets <code>cursor: pointer</code> and <code>filter: brightness(0.96)</code> on hover — useful for chips that link somewhere. No additional class needed.</p><hr><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li>Lucide icons (for Type=Icon Left and Type=Dismissible) — included via the page&#39;s existing Lucide setup.</li><li>No design system component dependencies — Badge is atomic.</li></ul><hr><h2 id="history" tabindex="-1">History <a class="header-anchor" href="#history" aria-label="Permalink to &quot;History&quot;">​</a></h2><ul><li>2026-05-05 (initial Figma-verified spec): <code>get_metadata</code> + per-variant <code>get_design_context</code> on node <code>2580:8904</code> corrected several mistakes in an earlier draft (Icon Left state count, Default state coverage). Changed base <code>border: 1px solid transparent</code> → <code>border: 1px solid var(--ai-btn-primary-border)</code> to match Figma&#39;s binding; removed the <code>margin-right: -4px</code> on <code>.badge__close</code> that didn&#39;t appear in Figma.</li><li>2026-05-05 (designer update): State=Default removed from the Type=Default state row in the Figma component set; State=Default now exists only as the canvas for the Size demo. Default state recoloured from <code>surface-brand-soft-extra</code> / <code>surface-brand-dark</code> to <code>surface-info-soft</code> / <code>surface-info</code>. Demo HTML&#39;s &quot;Default&quot; badge entry removed from the Type=Default row; unused <code>.badge--border.badge--default</code> rule removed from CSS.</li><li>2026-05-05 (designer follow-up): State=Default text token changed from <code>--ai-surface-info</code> to <code>--ai-text-info</code> across all three sizes. Default and Info now share text colour but differ in background token.</li></ul>',54)])])}const p=t(r,[["render",i]]);export{g as __pageData,p as default};
